import GemFinderApp from './gem-finder-v7.jsx';

export default function App() {
  return <GemFinderApp />;
}

'use client';

import { useEffect, useState } from 'react';
import { FeedConfig } from '@/lib/bonafied/types';

const CATEGORY_OPTIONS = [
  { label: 'Business', value: 'BUSINESS' },
  { label: 'Technology', value: 'TECHNOLOGY' },
  { label: 'Music Industry', value: 'MUSIC_INDUSTRY' },
  { label: 'Podcast / Creator', value: 'PODCAST_CREATOR' }
] as const;

export default function AdminPage() {
  const [feeds, setFeeds] = useState<FeedConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState('');
  const [form, setForm] = useState({
    name: '',
    url: '',
    category: 'BUSINESS',
    credibilityScore: 0.75,
    active: true
  });

  const loadFeeds = async () => {
    const response = await fetch('/api/feeds', { cache: 'no-store' });
    const data = await response.json();
    setFeeds(data.feeds || []);
  };

  useEffect(() => {
    void (async () => {
      setLoading(true);
      try {
        await loadFeeds();
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  const createFeed = async () => {
    setMessage('Saving feed...');
    const response = await fetch('/api/feeds', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        ...form,
        credibilityScore: Number(form.credibilityScore)
      })
    });

    if (!response.ok) {
      const data = await response.json();
      setMessage(data.error || 'Could not add feed');
      return;
    }

    await loadFeeds();
    setMessage('Feed added.');
    setForm({
      name: '',
      url: '',
      category: form.category,
      credibilityScore: 0.75,
      active: true
    });
  };

  const toggleFeedActive = async (feed: FeedConfig) => {
    await fetch(`/api/feeds/${feed.id}`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ active: !feed.active })
    });

    await loadFeeds();
  };

  const runIngestion = async () => {
    setMessage('Running ingestion...');
    const response = await fetch('/api/ingest', {
      method: 'POST'
    });
    const data = await response.json();
    setMessage(
      `Ingestion complete: +${data.ingestedStories || 0} stories, ${data.clusteredSignals || 0} clusters (${data.ingestedAt}).`
    );
  };

  return (
    <div className="admin-wrap">
      <h1 style={{ fontSize: 32, marginTop: 0, letterSpacing: '-0.02em' }}>BONAFIED Admin</h1>
      <p style={{ color: 'var(--text-secondary)', marginTop: 8 }}>
        Configure RSS feeds and run ingestion for THE WIRE.
      </p>

      <section className="admin-card" style={{ marginTop: 18 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 10 }}>
          <h2 style={{ margin: 0, fontSize: 18 }}>Feed Configuration</h2>
          <button className="small-btn primary" onClick={() => void runIngestion()}>
            Ingest Now
          </button>
        </div>

        <div className="admin-form">
          <input
            placeholder="Feed Name"
            value={form.name}
            onChange={(event) => setForm((current) => ({ ...current, name: event.target.value }))}
          />
          <input
            placeholder="RSS URL"
            value={form.url}
            onChange={(event) => setForm((current) => ({ ...current, url: event.target.value }))}
          />

          <select
            value={form.category}
            onChange={(event) => setForm((current) => ({ ...current, category: event.target.value as typeof form.category }))}
          >
            {CATEGORY_OPTIONS.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>

          <input
            type="number"
            min="0"
            max="1"
            step="0.01"
            value={form.credibilityScore}
            onChange={(event) =>
              setForm((current) => ({
                ...current,
                credibilityScore: Number(event.target.value)
              }))
            }
          />
        </div>

        <div style={{ marginTop: 10 }}>
          <button className="small-btn" onClick={() => void createFeed()}>
            Add Feed
          </button>
        </div>

        {message ? <div style={{ marginTop: 12, color: 'var(--text-secondary)', fontSize: 13 }}>{message}</div> : null}

        {loading ? (
          <div style={{ marginTop: 18, color: 'var(--text-tertiary)' }}>Loading feeds...</div>
        ) : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Category</th>
                <th>Credibility</th>
                <th>Active</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {feeds.map((feed) => (
                <tr key={feed.id}>
                  <td>
                    {feed.name}
                    <div style={{ color: 'var(--text-tertiary)', fontSize: 11, marginTop: 4 }}>{feed.url}</div>
                  </td>
                  <td>{feed.category}</td>
                  <td>{feed.credibilityScore.toFixed(2)}</td>
                  <td>{feed.active ? 'Yes' : 'No'}</td>
                  <td>
                    <button className="small-btn" onClick={() => void toggleFeedActive(feed)}>
                      {feed.active ? 'Disable' : 'Enable'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </section>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

export const runtime = 'nodejs';

const requestSchema = z.object({
  prompt: z.string().trim().min(1).max(30000),
  model: z.string().trim().min(1).max(120).default('claude-sonnet-4-20250514'),
  maxTokens: z.number().int().positive().max(4096).default(1200),
  apiKey: z.string().trim().max(300).optional().default('')
});

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = requestSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid AI payload', details: parsed.error.issues }, { status: 400 });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.ANTHROPIC_API_KEY || '').trim();
  if (!key) {
    return NextResponse.json({ error: 'Missing Anthropic API key.' }, { status: 400 });
  }

  try {
    const upstream = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model,
        max_tokens: maxTokens,
        messages: [{ role: 'user', content: prompt }]
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `Anthropic error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw) as { error?: { message?: string } };
        msg = parsedError?.error?.message || msg;
      } catch {}
      return NextResponse.json({ error: msg }, { status: upstream.status });
    }

    const data = JSON.parse(raw) as { content?: Array<{ type?: string; text?: string }> };
    const text =
      data?.content
        ?.map((item) => (item?.type === 'text' ? item.text || '' : ''))
        .filter(Boolean)
        .join('\n') || 'No response.';

    return NextResponse.json({ ok: true, text });
  } catch (error) {
    console.error('Anthropic proxy failed', error);
    return NextResponse.json({ error: 'AI proxy request failed.' }, { status: 502 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

export const runtime = 'nodejs';

const requestSchema = z.object({
  prompt: z.string().trim().min(1).max(30000),
  model: z.string().trim().min(1).max(120).default('gpt-4.1'),
  maxTokens: z.number().int().positive().max(4096).default(1200),
  apiKey: z.string().trim().max(300).optional().default('')
});

type OpenAIResponse = {
  output_text?: string;
  output?: Array<{
    type?: string;
    content?: Array<{ type?: string; text?: string }>;
  }>;
};

function parseOpenAIResponseText(payload: OpenAIResponse): string {
  if (typeof payload?.output_text === 'string' && payload.output_text.trim()) {
    return payload.output_text.trim();
  }
  const parts: string[] = [];
  (payload?.output || []).forEach((item) => {
    if (item?.type !== 'message') return;
    (item?.content || []).forEach((content) => {
      if ((content?.type === 'output_text' || content?.type === 'text') && content?.text) {
        parts.push(content.text);
      }
    });
  });
  return parts.join('\n').trim() || 'No response.';
}

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = requestSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid AI payload', details: parsed.error.issues }, { status: 400 });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.OPENAI_API_KEY || '').trim();
  if (!key) {
    return NextResponse.json({ error: 'Missing OpenAI API key.' }, { status: 400 });
  }

  try {
    const upstream = await fetch('https://api.openai.com/v1/responses', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${key}`
      },
      body: JSON.stringify({
        model,
        input: prompt,
        max_output_tokens: maxTokens
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `OpenAI error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw) as { error?: { message?: string } | string };
        const nested = typeof parsedError?.error === 'string' ? parsedError.error : parsedError?.error?.message;
        msg = nested || msg;
      } catch {}
      return NextResponse.json({ error: msg }, { status: upstream.status });
    }

    const data = JSON.parse(raw) as OpenAIResponse;
    const text = parseOpenAIResponseText(data);
    return NextResponse.json({ ok: true, text });
  } catch (error) {
    console.error('OpenAI proxy failed', error);
    return NextResponse.json({ error: 'AI proxy request failed.' }, { status: 502 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { getArAuthUserById, updateArUserByAdmin } from '@/lib/bonafied/repository';

const patchSchema = z.object({
  role: z.enum(['admin', 'editor', 'viewer']).optional(),
  active: z.boolean().optional(),
  password: z.string().min(8).max(120).optional()
});

export async function PATCH(req: NextRequest, ctx: { params: Promise<{ userId: string }> }) {
  const adminUserId = req.cookies.get('ar_user')?.value || '';
  const actor = await getArAuthUserById(adminUserId);
  if (!actor || !actor.active) {
    return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
  }
  if (actor.role !== 'admin') {
    return NextResponse.json({ error: 'Admin access required' }, { status: 403 });
  }

  const payload = await req.json().catch(() => null);
  const parsed = patchSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid patch payload', details: parsed.error.issues }, { status: 400 });
  }

  const { userId } = await ctx.params;
  const result = await updateArUserByAdmin(actor.userId, userId, parsed.data);
  if (!result.ok) {
    const status = result.error === 'User not found' ? 404 : result.error.includes('Admin') ? 403 : 400;
    return NextResponse.json({ error: result.error }, { status });
  }

  return NextResponse.json({ ok: true });
}

import crypto from 'node:crypto';
import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { getArAuthUserById, listArUsersForAdmin, registerArUser } from '@/lib/bonafied/repository';

const createSchema = z.object({
  email: z.string().email().max(220),
  role: z.enum(['admin', 'editor', 'viewer']).optional(),
  active: z.boolean().optional(),
  password: z.string().min(8).max(120).optional()
});

function tempPassword(): string {
  const seed = crypto.randomBytes(10).toString('base64url');
  return `${seed}A1!`;
}

export async function GET(req: NextRequest) {
  const adminUserId = req.cookies.get('ar_user')?.value || '';
  const actor = await getArAuthUserById(adminUserId);
  if (!actor || !actor.active) {
    return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
  }
  if (actor.role !== 'admin') {
    return NextResponse.json({ error: 'Admin access required' }, { status: 403 });
  }

  const result = await listArUsersForAdmin(actor.userId);
  if (!result.ok) {
    return NextResponse.json({ error: result.error }, { status: 403 });
  }
  return NextResponse.json({ ok: true, users: result.users });
}

export async function POST(req: NextRequest) {
  const adminUserId = req.cookies.get('ar_user')?.value || '';
  const actor = await getArAuthUserById(adminUserId);
  if (!actor || !actor.active) {
    return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
  }
  if (actor.role !== 'admin') {
    return NextResponse.json({ error: 'Admin access required' }, { status: 403 });
  }

  const payload = await req.json().catch(() => null);
  const parsed = createSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid user payload', details: parsed.error.issues }, { status: 400 });
  }

  const generated = !parsed.data.password;
  const password = parsed.data.password || tempPassword();
  const result = await registerArUser(parsed.data.email, password, {
    createdByUserId: actor.userId,
    role: parsed.data.role,
    active: parsed.data.active
  });
  if (!result.ok) {
    const status = result.error === 'Account already exists' ? 409 : result.error.includes('admin') ? 403 : 400;
    return NextResponse.json({ error: result.error }, { status });
  }

  return NextResponse.json({
    ok: true,
    user: { userId: result.userId, email: result.email, role: result.role },
    generatedPassword: generated ? password : undefined
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { loginArUser } from '@/lib/bonafied/repository';

const schema = z.object({
  email: z.string().email().max(220),
  password: z.string().min(1).max(120)
});

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = schema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid login payload', details: parsed.error.issues }, { status: 400 });
  }

  const result = await loginArUser(parsed.data.email, parsed.data.password);
  if (!result.ok) {
    const status = result.error === 'Email is not allowed for this workspace' ? 403 : 401;
    return NextResponse.json({ error: result.error }, { status });
  }

  const secure = process.env.NODE_ENV === 'production';
  const response = NextResponse.json({ ok: true, userId: result.userId, email: result.email, role: result.role });
  response.cookies.set('ar_user', result.userId, {
    httpOnly: true,
    secure,
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 24 * 30
  });
  response.cookies.set('ar_email', result.email, {
    httpOnly: true,
    secure,
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 24 * 30
  });
  response.cookies.set('ar_role', result.role, {
    httpOnly: true,
    secure,
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 24 * 30
  });

  return response;
}

