      const res = await fetch('/api/ar/admin/users', { method: 'GET' });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) {
        setError(data.error || 'Could not load users');
        return;
      }
      setUsers(data.users || []);
    } catch {
      setError('Network error loading users');
    } finally {
      setLoading(false);
    }
