  useEffect(() => {
    void load();
  }, []);

  const createUser = async () => {
    const cleanEmail = email.trim().toLowerCase();
    if (!cleanEmail) return;
    setCreateLoading(true);
    setError('');
    setStatus('');
    setGeneratedPassword('');
    try {
      const res = await fetch('/api/ar/admin/users', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: cleanEmail,
          role,
