import { getRedisClient } from '@/lib/bonafied/redis';

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
}

const CACHE = new Map<string, CacheEntry<unknown>>();

export async function getCached<T>(key: string): Promise<T | null> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      const raw = await redis.get(key);
      if (!raw) {
        return null;
      }
      return JSON.parse(raw) as T;
    } catch {
      // fall through to memory cache
    }
  }

  const hit = CACHE.get(key);
  if (!hit) {
    return null;
  }
  if (Date.now() > hit.expiresAt) {
    CACHE.delete(key);
    return null;
  }
  return hit.value as T;
}

export async function setCached<T>(key: string, value: T, ttlMs: number): Promise<void> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      await redis.set(key, JSON.stringify(value), {
        PX: ttlMs
      });
      return;
    } catch {
      // fall through to memory cache
    }
  }

  CACHE.set(key, {
    value,
    expiresAt: Date.now() + ttlMs
  });
}

export async function invalidateByPrefix(prefix: string): Promise<void> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      const scanner = redis.scanIterator({
        MATCH: `${prefix}*`,
        COUNT: 100
      });
      for await (const key of scanner) {
        await redis.del(key);
      }
    } catch {
      // continue into memory invalidation
    }
  }

  for (const key of CACHE.keys()) {
    if (key.startsWith(prefix)) {
      CACHE.delete(key);
    }
  }
}

import { CATEGORY_KEYWORDS } from '@/lib/bonafied/constants';
import { BonafiedCategory } from '@/lib/bonafied/types';

const MUSIC_STRONG_TERMS = [
  'music industry',
  'record label',
  'billboard',
  'grammy',
  'tour',
  'album',
  'single',
  'royalty',
  'publishing rights',
  'streaming rights',
  'warner music',
  'universal music',
  'sony music',
  'spotify',
  'apple music'
];

const MUSIC_ENTERTAINMENT_NOISE = [
  'tv show',
  'television',
  'tv series',
  'series',
  'season finale',
  'episode',
  'box office',
  'movie',
  'film',
  'drama',
  'actor',
  'actress',
  'grey s anatomy',
  "grey's anatomy",
  "grey's",
  'netflix series'
];

const PODCAST_STRONG_TERMS = [
  'podcast',
  'creator economy',
  'youtube creator',
  'newsletter',
  'substack',
  'patreon',
  'ad reads',
  'subscriber'
];

export function classifyCategory(text: string, fallback?: BonafiedCategory): BonafiedCategory {
  const haystack = text.toLowerCase();
  const scores = new Map<BonafiedCategory, number>();

  let bestCategory: BonafiedCategory = fallback || 'TECHNOLOGY';
  let bestScore = -1;

  for (const [category, keywords] of Object.entries(CATEGORY_KEYWORDS) as Array<[
    BonafiedCategory,
    string[]
  ]>) {
    const score = keywords.reduce((acc, keyword) => acc + (haystack.includes(keyword) ? 1 : 0), 0);
    scores.set(category, score);
    if (score > bestScore) {
      bestScore = score;
      bestCategory = category;
    }
  }

  if (fallback) {
    const fallbackScore = scores.get(fallback) || 0;

    // Keep the feed's declared category unless the text strongly indicates another one.
    if (bestCategory !== fallback) {
      const notEnoughSignal = bestScore < 2;
      const weakMargin = bestScore - fallbackScore <= 1;
      if (notEnoughSignal || weakMargin) {
        return fallback;
      }
    }
  }

  return bestCategory;
}

export function categorySignalScore(text: string, category: BonafiedCategory): number {
  const haystack = text.toLowerCase();
  const keywords = CATEGORY_KEYWORDS[category] || [];
  let score = 0;
  for (const keyword of keywords) {
    if (haystack.includes(keyword)) {
      score += keyword.includes(' ') ? 2 : 1;
    }
  }

  if (category === 'MUSIC_INDUSTRY') {
    for (const keyword of MUSIC_STRONG_TERMS) {
      if (haystack.includes(keyword)) score += 2;
    }
  }
  if (category === 'PODCAST_CREATOR') {
    for (const keyword of PODCAST_STRONG_TERMS) {
      if (haystack.includes(keyword)) score += 2;
    }
  }

  return score;
}

export function isCategoryRelevant(text: string, category: BonafiedCategory): boolean {
  const haystack = text.toLowerCase();
  const score = categorySignalScore(text, category);

  if (category === 'MUSIC_INDUSTRY') {
    const strongMusic = MUSIC_STRONG_TERMS.some((term) => haystack.includes(term));
    const entertainmentNoise = MUSIC_ENTERTAINMENT_NOISE.some((term) => haystack.includes(term));
    if (entertainmentNoise && !strongMusic) {
      return false;
    }
    return strongMusic || score >= 2;
  }

  if (category === 'PODCAST_CREATOR') {
    const strongPodcast = PODCAST_STRONG_TERMS.some((term) => haystack.includes(term));
    return strongPodcast || score >= 2;
  }

  return score >= 1;
}

import crypto from 'node:crypto';
import { SignalCluster, StoryRecord } from '@/lib/bonafied/types';
import { cosineSimilarity, jaccardSimilarity, normalizeTitle, tokenize } from '@/lib/bonafied/text';

interface ClusterState {
  cluster: SignalCluster;
  titleTokens: string[];
  stories: StoryRecord[];
}

const MIN_SIMILARITY = 0.62;

export function clusterStories(stories: StoryRecord[]): {
  clusters: SignalCluster[];
  stories: StoryRecord[];
} {
  const sorted = [...stories].sort(
    (a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime()
  );

  const states: ClusterState[] = [];
  const seenByUrl = new Set<string>();
  const deduped: StoryRecord[] = [];

  for (const story of sorted) {
    const canonical = canonicalizeUrl(story.url);
    if (seenByUrl.has(canonical)) {
      continue;
    }
    seenByUrl.add(canonical);
    deduped.push(story);

    const storyTokens = tokenize(story.title);
    let bestState: ClusterState | null = null;
    let bestScore = 0;

    for (const state of states) {
      if (state.cluster.category !== story.category) {
        continue;
      }

      const score = similarityScore(storyTokens, state.titleTokens);
      if (score > bestScore) {
        bestScore = score;
        bestState = state;
      }
    }

    if (bestState && bestScore >= MIN_SIMILARITY) {
      bestState.stories.push(story);
      bestState.cluster.storyIds.push(story.id);
      if (!bestState.cluster.sources.includes(story.sourceName)) {
        bestState.cluster.sources.push(story.sourceName);
      }
      for (const entity of story.entities) {
        if (!bestState.cluster.entities.includes(entity)) {
          bestState.cluster.entities.push(entity);
        }
      }
      if (new Date(story.publishedAt).getTime() > new Date(bestState.cluster.latestPublishedAt).getTime()) {
        bestState.cluster.latestPublishedAt = story.publishedAt;
      }
      if (story.rankScore > getPrimary(bestState.stories).rankScore) {
        bestState.cluster.primaryStoryId = story.id;
        bestState.cluster.headline = story.title;
      }
      bestState.titleTokens = tokenize(bestState.cluster.headline);
      continue;
    }

    const clusterId = `cluster_${crypto
      .createHash('sha1')
      .update(`${story.category}:${normalizeTitle(story.title)}`)
      .digest('hex')
      .slice(0, 12)}`;

    states.push({
      stories: [story],
      titleTokens: tokenize(story.title),
      cluster: {
        id: clusterId,
        category: story.category,
        headline: story.title,
        primaryStoryId: story.id,
        storyIds: [story.id],
        sources: [story.sourceName],
        entities: [...story.entities],
        score: story.rankScore,
        latestPublishedAt: story.publishedAt
      }
    });
  }

  const clusterMap = new Map<string, SignalCluster>();
  for (const state of states) {
    clusterMap.set(state.cluster.id, state.cluster);
  }

  return {
    clusters: [...clusterMap.values()],
    stories: deduped
  };
}

function getPrimary(stories: StoryRecord[]): StoryRecord {
  return [...stories].sort((a, b) => b.rankScore - a.rankScore)[0] || stories[0];
}

function canonicalizeUrl(value: string): string {
  try {
    const url = new URL(value);
    url.hash = '';
    url.search = '';
    return url.toString();
  } catch {
    return value;
  }
}

function similarityScore(leftTokens: string[], rightTokens: string[]): number {
  const jaccard = jaccardSimilarity(leftTokens, rightTokens);
  const cosine = cosineSimilarity(leftTokens, rightTokens);
  return jaccard * 0.46 + cosine * 0.54;
}

import { cleanText } from '@/lib/bonafied/text';

const KNOWN_ENTITIES = [
  'Apple',
  'Google',
  'Meta',
  'OpenAI',
  'Microsoft',
  'Amazon',
  'Spotify',
  'YouTube',
  'TikTok',
  'Substack',
  'Patreon',
  'Nvidia',
  'Reuters',
  'CNBC',
  'Billboard',
  'Podnews',
  'Universal',
  'Merlin',
  'Federal Reserve',
  'Wall Street Journal'
];

const NOISY_ENTITY_TERMS = new Set([
  'the',
  'for',
  'now',
  'what',
  'less',
  'continue',
  'american',
  'california',
  'san',
  'francisco',
  'company',
  'companies',
  'day',
  'days',
  'week',
  'weeks',
  'month',
  'months',
  'year',
  'years',
  'report',
  'reports',
  'analyst',
  'analysts',
  'update',
  'updates',
  'story',
  'stories'
]);

export function extractEntities(input: string): string[] {
  const text = cleanText(input);
  const found = new Set<string>();

  for (const entity of KNOWN_ENTITIES) {
    const expression = new RegExp(`\\b${escapeRegExp(entity)}\\b`, 'i');
    if (expression.test(text)) {
      found.add(entity);
    }
  }

  const properNounPhrases = text.match(/\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b/g) || [];
  for (const candidate of properNounPhrases) {
    if (candidate.length < 3 || candidate.length > 40) {
      continue;
    }
    const words = candidate.trim().split(/\s+/).filter(Boolean);
    if (!words.length) {
      continue;
    }
    const first = words[0].toLowerCase();
    if (NOISY_ENTITY_TERMS.has(first) && words.length <= 2) {
      continue;
    }
    if (words.length === 1 && NOISY_ENTITY_TERMS.has(first)) {
      continue;
    }
    if (/^(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)$/i.test(candidate)) {
      continue;
    }
    found.add(candidate.trim());
    if (found.size > 16) {
      break;
    }
  }

  const acronymCandidates = text.match(/\b[A-Z0-9]{2,6}\b/g) || [];
  for (const candidate of acronymCandidates) {
    const upper = candidate.toUpperCase();
    const lower = upper.toLowerCase();
    if (NOISY_ENTITY_TERMS.has(lower)) {
      continue;
    }
    if (!/[A-Z]/.test(upper)) {
      continue;
    }
    found.add(upper);
    if (found.size > 16) {
      break;
    }
  }

  return [...found].slice(0, 14);
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

