  link?: string;
  pubDate?: string;
  isoDate?: string;
  contentSnippet?: string;
  content?: string;
  creator?: string;
  enclosure?: {
    url?: string;
    type?: string;
  };
  ['media:content']?: Array<{ $?: { url?: string } }>;
}

interface ProviderStory {
  title: string;
  url: string;
  publishedAt: string;
  description?: string;
  imageUrl?: string;
  sourceName: string;
  sourceUrl: string;
  categoryHint: BonafiedCategory;
}

