  channel: Channel;
  timezone: string;
  only24h: boolean;
  search?: string;
  limit?: number;
  userId?: string;
}

export interface SignalResponse {
  generatedAt: string;
  timezone: string;
  channel: Channel;
  hero: StoryWithCluster | null;
  rows: Array<{
    channel: Channel;
    title: string;
    stories: StoryWithCluster[];
  }>;
  newSignalCount: number;
}

export interface SearchResult {
  id: string;
  title: string;
  type: 'story' | 'entity' | 'topic';
  subtitle: string;
}

