const baseUrl = process.env.APP_URL || process.env.NEXT_PUBLIC_APP_URL || 'http://127.0.0.1:3000';
const secret = process.env.INGEST_CRON_SECRET || process.env.CRON_SECRET || '';
const intervalMinutes = Number(process.env.INGEST_INTERVAL_MINUTES || 15);
const intervalMs = Math.max(1, intervalMinutes) * 60 * 1000;

async function triggerIngestion(options = { quietNetworkErrors: false }) {
  const started = new Date();
  try {
    const response = await fetch(`${baseUrl.replace(/\/$/, '')}/api/cron/ingest`, {
      method: 'POST',
      headers: secret ? { Authorization: `Bearer ${secret}` } : {}
    });

    const data = await response.json().catch(() => ({}));
    if (!response.ok) {
      console.error(`[ingest-worker] ${started.toISOString()} failed`, response.status, data);
      return false;
    }

    console.log(
      `[ingest-worker] ${started.toISOString()} ok +${data.ingestedStories || 0} stories, clusters ${
        data.clusteredSignals || 0
      }`
    );
    return true;
  } catch (error) {
    if (options.quietNetworkErrors) {
      console.warn(`[ingest-worker] ${started.toISOString()} waiting for app readiness`);
    } else {
      console.error(`[ingest-worker] ${started.toISOString()} error`, error);
    }
    return false;
  }
}

async function warmupAndTrigger() {
  const retries = 8;
  for (let attempt = 1; attempt <= retries; attempt += 1) {
    const ok = await triggerIngestion({ quietNetworkErrors: true });
    if (ok) {
      return;
    }
    await new Promise((resolve) => setTimeout(resolve, 5000));
  }
}

console.log(`[ingest-worker] started for ${baseUrl} every ${intervalMinutes} minute(s)`);
await warmupAndTrigger();
setInterval(triggerIngestion, intervalMs);

const base = (process.env.SMOKE_BASE_URL || 'http://127.0.0.1:3100').replace(/\/$/, '');
const secret = process.env.INGEST_CRON_SECRET || process.env.CRON_SECRET || 'change-me';

const checks = [
  {
    name: 'root redirect',
    request: () => fetch(`${base}/`, { redirect: 'manual' }),
    validate: async (res) => {
      if (!(res.status === 307 || res.status === 308)) {
        throw new Error(`expected redirect, got ${res.status}`);
      }
      const location = res.headers.get('location') || '';
      if (!location.includes('/news')) {
        throw new Error(`expected redirect to /news, got ${location}`);
      }
      return `redirect ${res.status} -> ${location}`;
    }
  },
  {
    name: 'signals live',
    request: () => fetch(`${base}/api/signals/live`),
    validate: async (res) => {
      if (!res.ok) {
        throw new Error(`status ${res.status}`);
      }
      const body = await res.json();
      if (typeof body.ingestCounter !== 'number') {
        throw new Error('missing ingestCounter');
      }
      return `ingestCounter=${body.ingestCounter}, recentCount=${body.recentCount}`;
    }
  },
  {
    name: 'signals payload',
    request: () =>
      fetch(
        `${base}/api/signals?channel=TODAY&timezone=${encodeURIComponent('America/Chicago')}&only24h=true&userId=smoke-user`
      ),
    validate: async (res) => {
      if (!res.ok) {
        throw new Error(`status ${res.status}`);
      }
      const body = await res.json();
      const heroTitle = body?.hero?.title || 'none';
      const rowCount = Array.isArray(body?.rows) ? body.rows.length : 0;
      return `hero=${heroTitle.slice(0, 70)}${heroTitle.length > 70 ? '...' : ''}, rows=${rowCount}`;
    }
  },
  {
    name: 'cron ingest',
    request: () =>
      fetch(`${base}/api/cron/ingest`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${secret}`
        }
      }),
    validate: async (res) => {
      if (!res.ok) {
        throw new Error(`status ${res.status}`);
      }
      const body = await res.json();
      if (!body.ok) {
        throw new Error('ok flag missing');
      }
      return `ingestedStories=${body.ingestedStories}, clusters=${body.clusteredSignals}`;
    }
  }
];

console.log(`BONAFIED smoke: ${base}`);

let failures = 0;
for (const check of checks) {
  try {
    const res = await check.request();
    const detail = await check.validate(res);
    console.log(`PASS  ${check.name}  ${detail}`);
  } catch (error) {
    failures += 1;
    console.error(`FAIL  ${check.name}  ${error instanceof Error ? error.message : String(error)}`);
  }
}

if (failures) {
  console.error(`Smoke failed (${failures} failing checks).`);
  process.exit(1);
}

console.log('Smoke passed.');

import crypto from 'node:crypto';
import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import cors from 'cors';
import express from 'express';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';
import nodemailer from 'nodemailer';
import { z } from 'zod';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const API_PORT = Number(process.env.PORT || process.env.API_PORT || 8787);
const API_HOST = process.env.API_HOST || '0.0.0.0';
const DATA_DIR = process.env.DATA_DIR
  ? path.resolve(process.env.DATA_DIR)
  : path.resolve(__dirname, '../data');
const LEADS_FILE = path.join(DATA_DIR, 'leads.ndjson');
const EVENTS_FILE = path.join(DATA_DIR, 'events.ndjson');

await fs.mkdir(DATA_DIR, { recursive: true });

const app = express();

app.use(
  helmet({
    contentSecurityPolicy: false
  })
);
app.use(cors());
app.use(express.json({ limit: '100kb' }));

const leadLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 15,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many submissions. Please try again in a bit.' }
});

const eventLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many analytics events.' }
});

const aiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 80,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many AI requests. Slow down and try again shortly.' }
});

const leadSchema = z.object({
  name: z.string().trim().min(2).max(120),
  email: z.string().trim().email().max(160),
  company: z.string().trim().min(2).max(120),
  brandWebsite: z.string().trim().max(220).optional().default(''),
  monthlySpend: z.string().trim().min(1).max(80),
  projectBrief: z.string().trim().min(10).max(2200),
  honeypot: z.string().max(0).optional().default(''),
  formStartedAt: z.number().int().positive()
});

const eventSchema = z.object({
  name: z.string().trim().min(1).max(120),
  payload: z.record(z.string(), z.union([z.string(), z.number(), z.boolean(), z.null(), z.undefined()])).default({}),
  timestamp: z.string().datetime(),
  path: z.string().max(300)
});

const aiRequestSchema = z.object({
  prompt: z.string().trim().min(1).max(30000),
  model: z.string().trim().min(1).max(120).default('claude-3-5-sonnet-latest'),
  maxTokens: z.number().int().positive().max(4096).default(1200),
  apiKey: z.string().trim().max(300).optional().default('')
});

const parseOpenAIResponseText = (payload) => {
  if (typeof payload?.output_text === 'string' && payload.output_text.trim()) {
    return payload.output_text.trim();
  }
  const parts = [];
  (payload?.output || []).forEach((item) => {
    if (item?.type !== 'message') return;
    (item?.content || []).forEach((content) => {
      if (content?.type === 'output_text' && content?.text) parts.push(content.text);
      if (content?.type === 'text' && content?.text) parts.push(content.text);
    });
  });
  return parts.join('\n').trim() || 'No response.';
};

const smtpHost = process.env.SMTP_HOST;
const smtpPort = process.env.SMTP_PORT ? Number(process.env.SMTP_PORT) : undefined;
const smtpUser = process.env.SMTP_USER;
const smtpPass = process.env.SMTP_PASS;
const leadsTo = process.env.LEADS_TO;

const transporter =
  smtpHost && smtpPort && smtpUser && smtpPass
    ? nodemailer.createTransport({
        host: smtpHost,
        port: smtpPort,
        secure: smtpPort === 465,
        auth: {
          user: smtpUser,
          pass: smtpPass
        }
      })
    : null;

const appendNdjson = async (filepath, data) => {
  await fs.appendFile(filepath, `${JSON.stringify(data)}\n`, 'utf8');
};

const maybeSendLeadEmail = async (lead) => {
  if (!transporter || !leadsTo) {
    return;
  }

  await transporter.sendMail({
    from: process.env.SMTP_FROM || smtpUser,
    to: leadsTo,
    subject: `New Lead: ${lead.company} (${lead.name})`,
    text: [
      `Lead ID: ${lead.leadId}`,
      `Name: ${lead.name}`,
      `Email: ${lead.email}`,
      `Company: ${lead.company}`,
      `Website: ${lead.brandWebsite || 'n/a'}`,
      `Monthly Spend: ${lead.monthlySpend}`,
      '',
      'Brief:',
      lead.projectBrief
    ].join('\n')
  });
};

app.get('/api/health', (_req, res) => {
  res.json({ ok: true, timestamp: new Date().toISOString() });
});

app.post('/api/leads', leadLimiter, async (req, res) => {
  const parsed = leadSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid lead payload', details: parsed.error.issues });
  }

  const lead = parsed.data;

  if (lead.honeypot) {
    return res.status(202).json({ ok: true });
  }

  const elapsedMs = Date.now() - lead.formStartedAt;
  if (elapsedMs < 2000) {
    return res.status(400).json({ error: 'Submission rejected as suspicious.' });
  }

  const leadRecord = {
    leadId: `lead_${Date.now()}_${crypto.randomBytes(3).toString('hex')}`,
    name: lead.name,
    email: lead.email,
    company: lead.company,
    brandWebsite: lead.brandWebsite,
    monthlySpend: lead.monthlySpend,
    projectBrief: lead.projectBrief,
    createdAt: new Date().toISOString(),
    userAgent: req.get('user-agent') || '',
    ip: req.ip || ''
  };

  try {
    await appendNdjson(LEADS_FILE, leadRecord);
    await maybeSendLeadEmail(leadRecord);
    return res.status(201).json({ ok: true, leadId: leadRecord.leadId });
  } catch (error) {
    console.error('Lead write failed', error);
    return res.status(500).json({ error: 'Could not save lead.' });
  }
});

app.post('/api/events', eventLimiter, async (req, res) => {
  const parsed = eventSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid event payload' });
  }

  const event = {
    ...parsed.data,
    receivedAt: new Date().toISOString(),
    ip: req.ip || '',
    userAgent: req.get('user-agent') || ''
  };

  try {
    await appendNdjson(EVENTS_FILE, event);
    return res.status(202).json({ ok: true });
  } catch (error) {
    console.error('Event write failed', error);
    return res.status(500).json({ error: 'Could not save event.' });
  }
});

app.post('/api/ai/anthropic', aiLimiter, async (req, res) => {
  const parsed = aiRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid AI payload', details: parsed.error.issues });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.ANTHROPIC_API_KEY || '').trim();
  if (!key) {
    return res.status(400).json({ error: 'Missing Anthropic API key.' });
  }

  try {
    const upstream = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model,
        max_tokens: maxTokens,
        messages: [{ role: 'user', content: prompt }]
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `Anthropic error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw);
        msg = parsedError?.error?.message || msg;
      } catch {}
      return res.status(upstream.status).json({ error: msg });
    }

    let data;
    try {
      data = JSON.parse(raw);
    } catch {
      return res.status(502).json({ error: 'Invalid AI response format.' });
    }

    const text =
      data?.content
        ?.map((item) => (item?.type === 'text' ? item.text : ''))
        .filter(Boolean)
        .join('\n') || 'No response.';
    return res.json({ ok: true, text });
  } catch (error) {
    console.error('Anthropic proxy failed', error);
    return res.status(502).json({ error: 'AI proxy request failed.' });
  }
});

app.post('/api/ai/openai', aiLimiter, async (req, res) => {
  const parsed = aiRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid AI payload', details: parsed.error.issues });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.OPENAI_API_KEY || '').trim();
  if (!key) {
    return res.status(400).json({ error: 'Missing OpenAI API key.' });
  }

  try {
    const upstream = await fetch('https://api.openai.com/v1/responses', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${key}`
      },
      body: JSON.stringify({
        model,
        input: prompt,
        max_output_tokens: maxTokens
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `OpenAI error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw);
        msg = parsedError?.error?.message || parsedError?.error || msg;
      } catch {}
      return res.status(upstream.status).json({ error: msg });
    }

    let data;
    try {
      data = JSON.parse(raw);
    } catch {
      return res.status(502).json({ error: 'Invalid AI response format.' });
    }

    const text = parseOpenAIResponseText(data);
    return res.json({ ok: true, text });
  } catch (error) {
    console.error('OpenAI proxy failed', error);
    return res.status(502).json({ error: 'AI proxy request failed.' });
  }
});

const server = app.listen(API_PORT, API_HOST, () => {
  console.log(`API listening on http://${API_HOST}:${API_PORT}`);
});

server.on('error', (error) => {
  console.error('API failed to start:', error);
  process.exit(1);
});

import { GoogleGenAI, Type } from "@google/genai";
import { CloudType } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

interface GeneratedIdea {
  title: string;
  description: string;
  emoji: string;
  type: CloudType;
  cost?: number;
}

interface DeepResponse {
    systemName: string;
    theme: 'warm' | 'cool' | 'dark' | 'nature';
    ideas: GeneratedIdea[];
}

export const generateIdeas = async (topic: string, isDeepThink: boolean = false): Promise<DeepResponse | GeneratedIdea[]> => {
  if (!apiKey) {
    console.warn("No API Key available for Gemini.");
    return [];
  }

  try {
    if (isDeepThink) {
        // --- GEMINI 3 PRO PREVIEW WITH THINKING ---
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: `Analyze the topic "${topic}" deeply. Create a comprehensive "Weather System" (a category or zone) for this topic.
            Then, brainstorm 5-8 distinct, actionable sub-items (clouds) that belong in this system.

            Structure the response to include:
            1. A system name (creative title for the zone).
            2. A visual theme ('warm', 'cool', 'dark', 'nature').
            3. A list of cloud ideas, where each has a type (cumulus/thought/nimbus/cirrus/storm/stratus/lenticular), title, description, emoji, and optional cost.`,
            config: {
                thinkingConfig: { thinkingBudget: 32768 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        systemName: { type: Type.STRING },
                        theme: { type: Type.STRING, enum: ['warm', 'cool', 'dark', 'nature'] },
                        ideas: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    title: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    emoji: { type: Type.STRING },
                                    cost: { type: Type.NUMBER, nullable: true },
                                    type: { type: Type.STRING, enum: ['cumulus', 'thought', 'nimbus', 'cirrus', 'storm', 'stratus', 'lenticular'] }
                                },
                                required: ['title', 'description', 'emoji', 'type']
                            }
                        }
                    },
                    required: ['systemName', 'theme', 'ideas']
                }
            }
        });

        const text = response.text;
        if (!text) return [];
        return JSON.parse(text) as DeepResponse;

    } else {
        // --- GEMINI 3 FLASH (Fast) ---
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Brainstorm 3-5 creative and distinct tasks or ideas related to: "${topic}". 
            Assign a 'type' based on the nature of the task:
            - 'cumulus' for standard tasks.
            - 'thought' for ideas needing consideration.
            - 'nimbus' for heavy/expensive projects.
            - 'cirrus' for quick/light tasks.
            - 'storm' for problems or cancellations.
            - 'stratus' for background/foundation tasks.
            - 'lenticular' for weird/unique ideas.

            Assign a rough estimated cost (number) ONLY if relevant (e.g. for expenses). Otherwise leave cost null.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        emoji: { type: Type.STRING },
                        cost: { type: Type.NUMBER, nullable: true },
                        type: { type: Type.STRING, enum: ['cumulus', 'thought', 'nimbus', 'cirrus', 'storm', 'stratus', 'lenticular'] }
                    },
                    required: ['title', 'description', 'emoji', 'type']
                }
                }
            }
        });

        const text = response.text;
        if (!text) return [];
        return JSON.parse(text) as GeneratedIdea[];
    }
  } catch (error) {
    console.error("Gemini Brainstorm Error:", error);
    return [];
  }
};

export const expandIdea = async (parentIdea: string, parentDesc: string): Promise<GeneratedIdea[]> => {
    if (!apiKey) return [];
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `The user has an idea: "${parentIdea}" (${parentDesc}). 
            Generate 3-4 concrete next steps, sub-tasks, or related questions that branch off from this idea.
            Keep them short and punchy.
             Assign a 'type' based on the nature of the task:
            - 'cumulus' for standard tasks.
            - 'thought' for ideas needing consideration.
            - 'nimbus' for heavy/expensive projects.
            - 'cirrus' for quick/light tasks.
            - 'storm' for problems or cancellations.`,
             config: {
                responseMimeType: "application/json",
                responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        emoji: { type: Type.STRING },
                        cost: { type: Type.NUMBER, nullable: true },
                        type: { type: Type.STRING, enum: ['cumulus', 'thought', 'nimbus', 'cirrus', 'storm', 'stratus', 'lenticular'] }
                    },
                    required: ['title', 'description', 'emoji', 'type']
                }
                }
            }
        });
        const text = response.text;
        if (!text) return [];
        return JSON.parse(text) as GeneratedIdea[];
    } catch (e) {
        console.error("Expand Error", e);
        return [];
    }
}

export type CloudType = 'cumulus' | 'thought' | 'nimbus' | 'cirrus' | 'storm' | 'stratus' | 'lenticular' | 'mammatus' | 'fractal';
export type SkyMode = 'day' | 'sunset' | 'night' | 'stormy' | 'aurora' | 'golden' | 'midnight' | 'mist';
export type CloudStatus = 'backlog' | 'active' | 'blocked' | 'done';
export type CloudPriority = 'low' | 'medium' | 'high';

export interface Viewport {
  x: number;
  y: number;
  scale: number;
}

export interface Connection {
  id: string;
  from: string;
  to: string;
  type: 'curve' | 'lightning' | 'rain';
}

export interface CloudData {
  id: string;
  type: CloudType;
  title: string;
  description?: string;
  subItems?: string[]; // Raindrops (sub-tasks)
  cost?: number; 
  emoji?: string; // Now Optional
  imageUrl?: string; // New: Image support
  x: number; // Canvas coordinate X
  y: number; // Canvas coordinate Y
  vx?: number; // Velocity X
  vy?: number; // Velocity Y
  color?: string; 
  tags?: string[];
  width?: number;
  height?: number;
  status?: CloudStatus;
  priority?: CloudPriority;
  dueDate?: string;
  owner?: string;
  effort?: number; // 1-10
  impact?: number; // 1-10
  confidence?: number; // 1-10
}

export interface WeatherSystem {
  id: string;
  title: string;
  x: number;
  y: number;
  radius: number;
  theme: 'warm' | 'cool' | 'dark' | 'nature';
}

export interface SkyState {
  clouds: CloudData[];
  systems: WeatherSystem[];
  connections: Connection[];
}

export interface CloudShapeConfig {
  circles: { cx: number; cy: number; r: number }[];
  baseWidth: number;
  baseHeight: number;
  viewBox: string;
}

